import { useEffect, useState } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function DriverRoute() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [task, setTask] = useState(null);

  const getTask = async () => {
    try {
      const res = await axios.get(
        "http://localhost:3000/api/driver/today-task"
      );

      const found = res.data.requests.find(
        (item) => item._id === id
      );

      setTask(found);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getTask();
  }, []);

  const markArrived = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/arrived/${id}`
      );

      setTask(res.data.data);
    } catch (error) {
      console.log(error);
    }
  };

  const markCompleted = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/completed/${id}`
      );

      setTask(res.data.data);

      setTimeout(() => {
        navigate("/driver-dashboard");
      }, 2000);
    } catch (error) {
      console.log(error);
    }
  };

  if (!task) {
    return (
      <div className="min-h-screen flex justify-center items-center text-xl font-bold">
        Loading...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#4CBB17]/10">

      {/* Route Header */}
      <div className="bg-green-700 text-white py-4 px-6 shadow">
        <h2 className="text-xl font-bold text-center">
          🚛 MANIT Bhopal → {task.location?.location}
        </h2>
      </div>

      {/* Live Location */}
      <div className="mx-4 mt-4 bg-white rounded-2xl shadow-lg p-5">
        <h3 className="text-lg font-bold text-green-700 mb-3">
          📍 Live Location
        </h3>

        <p className="text-gray-700">
          Driver Current Position
        </p>

        <p className="text-sm text-gray-600 mt-2">
          Latitude : 23.2167
        </p>

        <p className="text-sm text-gray-600">
          Longitude : 77.4061
        </p>

        <button
          onClick={() =>
            window.open(
              `https://www.google.com/maps/dir/23.2167,77.4061/${task.location?.latitude},${task.location?.longitude}`,
              "_blank"
            )
          }
          className="mt-4 w-full bg-blue-600 hover:bg-blue-700 text-white py-3 rounded-xl font-semibold"
        >
          Open Route
        </button>
      </div>

      {/* Action Section */}
      <div className="flex flex-col items-center mt-16">

        {task.arrivedAt && (
          <div className="bg-yellow-100 p-4 rounded-xl mb-4 w-80 text-center shadow">
            <p className="font-bold text-yellow-700">
              Arrived Time
            </p>

            <p className="mt-1">
              {new Date(task.arrivedAt).toLocaleString()}
            </p>
          </div>
        )}

        {task.completedAt && (
          <div className="bg-green-100 p-4 rounded-xl mb-4 w-80 text-center shadow">
            <p className="font-bold text-green-700">
              Completed Time
            </p>

            <p className="mt-1">
              {new Date(task.completedAt).toLocaleString()}
            </p>
          </div>
        )}

        {task.status === "Scheduled" && (
          <button
            onClick={markArrived}
            className="bg-yellow-500 hover:bg-yellow-600 text-white px-12 py-4 rounded-xl text-xl font-bold shadow-lg"
          >
            Arrived
          </button>
        )}

        {task.status === "Arrived" && (
          <button
            onClick={markCompleted}
            className="bg-green-600 hover:bg-green-700 text-white px-12 py-4 rounded-xl text-xl font-bold shadow-lg"
          >
            Completed
          </button>
        )}
      </div>
    </div>
  );
}
